import{_ as s,o as r,c as p,ag as o}from"./chunks/framework.ETe_P6d1.js";const n="/kaiping-reports/assets/1.CMjt_f1H.jpg",g="/kaiping-reports/assets/2.tBFiC_Se.jpg",_="/kaiping-reports/assets/3.C3a1h8LJ.jpg",e="/kaiping-reports/assets/5.Dw9McBF6.jpg",a="/kaiping-reports/assets/6.pv9wldmL.jpg",i="/kaiping-reports/assets/8.SPtYgqit.jpg",c="/kaiping-reports/assets/7.CLjTRMqz.jpg",C=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reports/马依然/马依然_赤坎古镇建筑调研报告.md","filePath":"reports/马依然/马依然_赤坎古镇建筑调研报告.md"}'),m={name:"reports/马依然/马依然_赤坎古镇建筑调研报告.md"};function l(d,t,f,j,k,S){return r(),p("div",null,[...t[0]||(t[0]=[o('<p><strong>专业调研报告内容：</strong></p><p><strong>一、</strong> <strong>引言</strong> 赤坎古镇位于广东省江门开平市潭江河畔，是一座具有370多年开埠历史、以华侨文化为主题的大型文化休闲度假区。古镇的格局与早期繁荣深受宗族文化影响，由上埠关族、下埠司徒氏两大家族在潭江东西两岸聚居竞争发展而成，形成了独特的“一江两埠”格局。古镇拥有规模较大、界面连续、保存较为完整的侨乡骑楼建筑群，现存600余座中西合璧的骑楼绵延约3公里，通过对历史建筑进行保护性修缮与活化利用，古镇已发展成为集文保展示、非遗体验、特色餐饮、沉浸式演艺等于一体的综合性旅游目的地。 <img src="'+n+'" alt="1"></p><p><img src="'+g+'" alt="2"> <img src="'+_+'" alt="3"><strong>二、</strong> <strong>空间类型与形态</strong> 从建筑类型来看，古镇核心街巷以骑楼街为主体，堤西路、中华路等主要街道骑楼连续分布，形成长约 3 公里的线性公共空间。骑楼底层立柱支撑形成连续廊檐，宽约 3-4 米，既为行人遮风挡雨，也成为商业活动的延伸空间。次级巷道狭窄曲折，宽度多在 1-2 米，连接主街与内部民居，空间尺度亲切，构成 “主街 — 次巷 — 内院” 的层级体系。街巷走向顺应水势，局部转折自然，满足高效的交通功能需求。 古镇建筑以骑楼为核心类型，多为 2-3 层，局部 4 层，采用 “下铺上宅、前铺后宅” 的复合空间模式。立面呈现强烈的中西合璧特征：底层为连续拱廊，借鉴古罗马建筑范式；二层及以上融入巴洛克浮雕、山花装饰、罗马柱式等西洋元素；顶部搭配岭南传统灰塑、瓦顶与满洲窗。单体建筑面宽窄、进深深，呈长筒型布局，内部常设天井采光通风，形成 “外欧内粤” 的空间特质。此外，司徒氏图书馆、关族图书馆等公共建筑，以葡萄牙建筑风格为主，兼具宗族象征与文化功能，成为古镇空间节点。</p><p><strong>三、</strong> <strong>建造材料与构造</strong></p><p>主体建造材料分为三个部分：</p><p>传统材料：清末建筑以砖木结构为主，墙体用青砖砌筑，木梁架支撑瓦顶。民国时期骑楼主体以红砖、青砖为墙体材料，柱、梁、楼板部分采用钢筋混凝土，兼顾坚固性与可塑性。屋面覆盖传统陶瓦，防水隔热；门窗多用硬木，搭配彩色玻璃、满洲窗，兼具装饰与实用功能。</p><p>外来材料：华侨归国建设时引入水泥、钢筋、玻璃等西洋建材，用于建筑立面装饰、结构加固与细节构建，如巴洛克式浮雕、罗马柱、铁艺栏杆等，丰富了建筑构造层次。</p><p>装饰材料：立面装饰以灰塑、石雕、木雕为主，灰塑用于山花、檐口，题材多为花鸟、几何纹样；石雕应用于柱础、门框；木雕集中于室内屏风、花窗，工艺精湛。</p><p><img src="'+e+'" alt="5"></p><p><strong>四、</strong> <strong>功能布局与使用方式</strong></p><p><strong>（一）历史功能布局</strong> 商业功能：主街骑楼底层为商铺，涵盖百货、银号、餐饮、杂货等业态，堤西路、中华路为核心商业区，曾是粤西重要商贸集散地。商铺采用 “前店后仓” 布局，前端营业，后端储物，功能紧凑。 居住功能：骑楼二、三层为居住空间，内部隔间、卧室、厨房齐全，满足商户家庭居住需求。镇区内部巷道分布传统民居，多为三合院、四合院布局，以宗族聚居为主。 公共功能：沿潭江设码头、渡口，承担水运交通功能；设有司徒氏图书馆、关族图书馆、商会、赤坎中学等公共建筑，满足文化、社交、教育需求；同时分布碉楼（如迎龙楼），兼具防御、防洪功能携程。</p><p><img src="'+a+'" alt="6"></p><p><img src="'+i+'" alt="8"><img src="'+c+'" alt="7"></p><p><strong>（二）传统使用方式</strong> 商业使用：骑楼商铺临街开门，廊檐作为临时经营、行人休憩空间。 居住使用：居住空间私密安静，与底层商业动静分区，居民日常出行、购物便捷，形成 “商住共生” 的生活模式。 公共活动：潭江沿岸、图书馆、码头为公共活动核心，宗族聚会、节庆仪式、商贸洽谈集中于此，强化社群凝聚力。</p><p><strong>（三）功能演变</strong> 20 世纪后期以来，因华侨外流、人口减少、建筑老化，古镇商业衰退、居住功能弱化，大量建筑闲置。传统 “商住共生” 模式瓦解，活力显著下降。</p><p><strong>五、</strong> <strong>现代生活或文旅利用与适应性改造</strong></p><p><strong>（一）文旅利用现状</strong> 2023 年赤坎华侨古镇（一期）试运营，2025 年正式运营，以 “保护优先、修旧如旧” 为原则，打造侨文化主题文旅综合体江门开平市人民政府。 业态布局：整合文保展示、非遗文创、精品民宿、特色餐饮、沉浸式演艺等复合型业态江门开平市人民政府。修缮后的骑楼分设华侨历史展馆、非遗工坊、文创商店、主题餐厅；司徒氏、关族图书馆改造为文化展厅。 文化体验：推出《归途》《水火秀》等沉浸式演艺，还原华侨历史；举办粤剧巡演、民俗游神等活动；保留电灯公司、电话公司、天宝银号等商号旧址，再现侨乡商埠风貌江门开平市人民政府。</p><p><strong>（二)适应性改造措施</strong> 建筑修缮改造：遵循 “修旧如旧”，修复骑楼立面、结构，更换腐朽构件，加固墙体与梁柱光明区政府。完善水电、排污、消防等基础设施，保留传统风貌的同时满足现代安全标准。 空间功能适配：将闲置骑楼改造为民宿、展馆、商铺，保留内部空间格局，优化采光、通风、隔音；拓宽局部巷道，增设休憩节点、标识系统，提升游览舒适度江门开平市人民政府。 材料与工艺传承：修缮中复用传统青砖、红砖，采用传统灰塑、木雕工艺；侨小馆等新建建筑筛选古旧青红砖 90 余万块，延续古镇材料肌理。</p>',18)])])}const u=s(m,[["render",l]]);export{C as __pageData,u as default};
